// Code_Normalize_Manifests (FINAL v2 - minimal schema, enterprise hardening)

const isDate = (s) => /^\d{4}-\d{2}-\d{2}$/.test(String(s || "").trim());
const isHex24 = (s) => /^[0-9a-f]{24}$/i.test(String(s || "").trim());
const toStr = (v) => (v ?? "").toString().trim();

const parseMaxRows = (v) => {
  let n = Number(String(v ?? 20).replace(/[^0-9]/g, ""));
  if (!Number.isFinite(n) || n <= 0) n = 20;
  if (n > 50) n = 50; // AI-SAFE cap
  return n;
};

// Required: token
const token = toStr($json.token);
if (!token) {
  return [{
    json: {
      ok: false,
      error: "token is required (Bearer JWT missing)",
      tokenPresent: false,
      tokenPrefix: null,
    }
  }];
}

const providerId = toStr($json.providerId);
const productId  = toStr($json.productId);

if (!providerId) return [{ json: { ok: false, error: "providerId is required", tokenPresent: true, tokenPrefix: token.slice(0, 12) } }];
if (!productId)  return [{ json: { ok: false, error: "productId is required", tokenPresent: true, tokenPrefix: token.slice(0, 12) } }];

if (!isHex24(providerId)) return [{ json: { ok: false, error: "providerId must be 24-hex", providerId, tokenPresent: true, tokenPrefix: token.slice(0, 12) } }];
if (!isHex24(productId))  return [{ json: { ok: false, error: "productId must be 24-hex", productId, tokenPresent: true, tokenPrefix: token.slice(0, 12) } }];

const dateFrom = toStr($json.dateFrom);
const dateTo   = toStr($json.dateTo || dateFrom);

if (!isDate(dateFrom)) return [{ json: { ok: false, error: "dateFrom must be YYYY-MM-DD", dateFrom, tokenPresent: true, tokenPrefix: token.slice(0, 12) } }];
if (!isDate(dateTo))   return [{ json: { ok: false, error: "dateTo must be YYYY-MM-DD", dateTo, tokenPresent: true, tokenPrefix: token.slice(0, 12) } }];

const maxRows = parseMaxRows($json.maxRows);

return [{
  json: {
    ok: true,
    token,
    tokenPresent: true,
    tokenPrefix: token.slice(0, 12),
    providerId,
    productId,
    dateFrom,
    dateTo,
    maxRows
  }
}];

// Code_AI_SAFE_Reducer_Manifests (FINAL v2) - KPIs + Top Table (AI-SAFE, minimal params)

const input = $items("Code_Normalize_Manifests")[0].json;

const maxRows = Number(input.maxRows ?? 20);
const data = $json;

const toIdShort = (id) => (id ? String(id).slice(-8) : null);
const getByPath = (obj, path) => path.split(".").reduce((a, k) => (a && a[k] !== undefined ? a[k] : undefined), obj);
const pick = (obj, paths) => {
  for (const p of paths) {
    const v = getByPath(obj, p);
    if (v !== undefined && v !== null && v !== "") return v;
  }
  return null;
};

const manifestsRaw =
  Array.isArray(data.tripManifests) ? data.tripManifests :
  Array.isArray(data.manifests) ? data.manifests :
  Array.isArray(data.items) ? data.items :
  [];

const rowsAll = manifestsRaw.map((m) => {
  const manifestId = pick(m, ["_id", "id", "tripManifestId"]);
  const tripId = pick(m, ["tripId", "trip._id", "trip.id", "departureId", "departures.0.id"]);

  const origin = pick(m, ["origin.name", "from.name", "departureStation.name", "origin", "from"]);
  const destination = pick(m, ["destination.name", "to.name", "arrivalStation.name", "destination", "to"]);

  const dep = pick(m, ["departureTime", "departure.time", "trip.departureTime", "trip.departure.time", "departures.0.departureTime"]);
  const arr = pick(m, ["arrivalTime", "arrival.time", "trip.arrivalTime", "trip.arrival.time", "departures.0.arrivalTime"]);

  const pax = Number(pick(m, ["pax", "paxCount", "passengersCount", "totalPassengers", "soldSeats", "ticketsSold", "summary.pax"]));
  const revenue = Number(pick(m, ["revenue", "totalAmount", "gross", "sales", "totalSales", "summary.revenue"]));

  const paxSafe = Number.isFinite(pax) ? pax : null;
  const revenueSafe = Number.isFinite(revenue) ? revenue : null;

  const route = (origin && destination) ? `${origin} → ${destination}` : null;
  const score = (revenueSafe ?? 0) * 1000000 + (paxSafe ?? 0);

  return {
    manifestId,
    manifestIdShort: toIdShort(manifestId),
    tripId,
    tripIdShort: toIdShort(tripId),
    route,
    departureTime: dep,
    arrivalTime: arr,
    pax: paxSafe,
    revenue: revenueSafe,
    score,
  };
});

const totalManifests = rowsAll.length;
const uniqueTrips = new Set(rowsAll.map(r => r.tripId).filter(Boolean)).size;
const totalPax = rowsAll.reduce((acc, r) => acc + (Number.isFinite(r.pax) ? r.pax : 0), 0);
const totalRevenue = rowsAll.reduce((acc, r) => acc + (Number.isFinite(r.revenue) ? r.revenue : 0), 0);

const rowsTop = [...rowsAll]
  .sort((a, b) => (b.score ?? 0) - (a.score ?? 0))
  .slice(0, maxRows)
  .map(({ score, ...r }) => r);

return [{
  json: {
    ok: true,
    params: {
      providerId: input.providerId,
      productId: input.productId,
      dateFrom: input.dateFrom,
      dateTo: input.dateTo,
      maxRows
    },
    kpis: { totalManifests, uniqueTrips, totalPax, totalRevenue },
    top: {
      columns: ["manifestIdShort","tripIdShort","route","departureTime","arrivalTime","pax","revenue"],
      rows: rowsTop
    }
  }
}];

// Code_Return_Error (FINAL)
return [{
  json: {
    ok: false,
    error: $json.error ?? "Normalize failed",
    details: $json
  }
}];

// Final_Output (FINAL) - unified response for ToolWorkflow

const j = $json ?? {};

// If previous node already marked ok:false (Normalize/IF branch)
if (j.ok === false) {
  return [{
    json: {
      ok: false,
      error: j.error ?? "Unknown error",
      details: j.details ?? j,
    }
  }];
}

// If previous node is success but doesn't include ok, force ok:true
return [{
  json: {
    ok: true,
    ...j
  }
}];

const token = ($json.token ?? "").toString().trim();

return [{
  json: {
    ...$json,
    authHeader: token ? `Bearer ${token}` : "",
  }
}];

